(function () {
  const videos = document.querySelectorAll('.lazy-video');
  const generateUrl = id => {
    const query = '?rel=0&showinfo=0&autoplay=1';
    return 'https://www.youtube.com/embed/' + id + query;
  };
  const createIframe = (id, title) => {
    const iframe = document.createElement('iframe');
    iframe.setAttribute('allowfullscreen', '');
    iframe.setAttribute('allow', 'autoplay; encrypted-media');
    iframe.setAttribute('frameborder', '0');
    iframe.setAttribute('title', title);
    iframe.setAttribute('src', generateUrl(id));
    iframe.setAttribute('tabindex', '0');
    return iframe;
  };
  videos.forEach(el => {
    const videoCode = el.getAttribute('data-video');
    if (!videoCode) return;
    el.addEventListener('click', e => {
      e.preventDefault();

      // Важно: убрать навигационное поведение якоря как можно раньше
      el.removeAttribute('href');
      if (el.dataset.loaded === '1') return;
      el.dataset.loaded = '1';
      const title = el.getAttribute('aria-label') || el.getAttribute('title') || 'Видео';
      const iframe = createIframe(videoCode, title);
      iframe.setAttribute('tabindex', '0');
      const picture = el.querySelector('picture');
      if (picture) picture.remove();
      const btn = el.querySelector('.ytb-btn');
      if (btn) btn.remove();
      el.appendChild(iframe);

      // Перенос фокуса чуть позже — часто работает стабильнее
      requestAnimationFrame(() => {
        iframe.focus({
          preventScroll: true
        });
      });
      el.removeAttribute('title');
      el.setAttribute('role', 'button');
    }, {
      once: true
    });
  });
})();

